&= \mathbf{A} (\mathbf{A} - 2 \mathbf{I}) \\
&= \mathbf{A} - 2 \mathbf{I} \\
&= \boxed{
\begin{pmatrix} 0 & 3 \\ 0 & -1 \end{pmatrix}
}.
\end{align*}

